#include <stdio.h>

const char* calculator(int a) {
    if (a % 3 == 0 || a % 7 == 0) {
        return "YES";
    }
    while (a >= 3) {
        a -= 7;
        if (a > 0 && a % 3 == 0) {
            return "YES";
        }
    }
    return "NO";
}

int main() {
    int t, a;
    scanf("%d", &t);
    while (t--) {
        scanf("%d", &a);
        printf("%s\n", calculator(a));
    }
    return 0;
}
